const toB64Url = (bytes) => btoa(String.fromCharCode(...bytes)).replaceAll("+", "-").replaceAll("/", "_").replaceAll("=", "");
const fromB64Url = (value) => {
  const bin = atob(value.replaceAll("-", "+").replaceAll("_", "/"));
  return Uint8Array.from(bin, (ch) => ch.charCodeAt(0));
};
const addCredential = async (db, cred, nowIso) => {
  await db.prepare(
    `INSERT INTO passkey_credentials
         (credential_id, user_id, public_key, sign_count, transports, device_name, created_at)
       VALUES (?, ?, ?, ?, ?, ?, ?)`
  ).bind(
    cred.credentialId,
    cred.userId,
    toB64Url(cred.publicKey),
    cred.counter,
    JSON.stringify(cred.transports),
    cred.deviceName,
    nowIso
  ).run();
};
const toStored = (r) => ({
  credentialId: r.credential_id,
  userId: r.user_id,
  publicKey: fromB64Url(r.public_key),
  counter: r.sign_count,
  transports: (() => {
    try {
      const t = JSON.parse(r.transports ?? "[]");
      return Array.isArray(t) ? t.filter((x) => typeof x === "string") : [];
    } catch {
      return [];
    }
  })()
});
const getCredential = async (db, credentialId) => {
  const r = await db.prepare("SELECT credential_id, user_id, public_key, sign_count, transports FROM passkey_credentials WHERE credential_id = ?").bind(credentialId).first();
  return r ? toStored(r) : null;
};
const listUserCredentials = async (db, userId) => {
  const r = await db.prepare("SELECT credential_id, transports FROM passkey_credentials WHERE user_id = ?").bind(userId).all();
  return (r.results ?? []).map((row) => ({
    id: row.credential_id,
    transports: (() => {
      try {
        const t = JSON.parse(row.transports ?? "[]");
        return Array.isArray(t) ? t.filter((x) => typeof x === "string") : [];
      } catch {
        return [];
      }
    })()
  }));
};
const bumpCounter = async (db, credentialId, counter, nowIso) => {
  await db.prepare("UPDATE passkey_credentials SET sign_count = ?, last_used_at = ? WHERE credential_id = ?").bind(counter, nowIso, credentialId).run();
};
const listUserPasskeys = async (db, userId) => {
  const r = await db.prepare("SELECT credential_id, device_name, created_at, last_used_at FROM passkey_credentials WHERE user_id = ? ORDER BY created_at").bind(userId).all();
  return (r.results ?? []).map((row) => ({
    id: row.credential_id,
    deviceName: row.device_name ?? "Passkey",
    createdAt: row.created_at,
    lastUsedAt: row.last_used_at
  }));
};
const deleteCredential = async (db, userId, credentialId) => {
  await db.prepare("DELETE FROM passkey_credentials WHERE credential_id = ? AND user_id = ?").bind(credentialId, userId).run();
};

